                    const parsedStagesFromDesc = (() => {
                      if (selectedJob.description && selectedJob.description.includes('===ETAPAS_JSON===')) {
                        try {
                          const part = selectedJob.description.split('===ETAPAS_JSON===')[1].split('===FIM_ETAPAS===')[0];
                          return JSON.parse(part);
                        } catch (e) {
                          console.error('Error parsing stages from description:', e);
                        }
                      }
                      return null;
                    })();

                    const stagesList: string[] = parsedStagesFromDesc || (Array.isArray(selectedJob.stages) 
                      ? selectedJob.stages 
                      : (typeof selectedJob.stages === 'string' 
                          ? JSON.parse(selectedJob.stages) 
                          : ['Análise de Currículo', 'Entrevista', 'Teste Técnico']));

                    const allColumns = [...stagesList, 'Contratado', 'Reprovado'];"
